package com.chaobo.scm.supplier.application.quality;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.integration.InboundEventPayloadStore;import com.chaobo.scm.supplier.application.masterdata.MasterDataEventConsumeLogPort;import com.chaobo.scm.supplier.application.shared.CommandContext;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.Set;
@Service public class QualitySourceEventConsumerApplicationService{private static final String CONSUMER="supplier-quality-source";private final MasterDataEventConsumeLogPort inbox;private final SupplierQualityIssueApplicationService issues;private final InboundEventPayloadStore payloads;public QualitySourceEventConsumerApplicationService(MasterDataEventConsumeLogPort inbox,SupplierQualityIssueApplicationService issues,InboundEventPayloadStore payloads){this.inbox=inbox;this.issues=issues;this.payloads=payloads;}@Transactional public void consume(QualitySourceEvent event){if(!Set.of("WMS","OMS").contains(event.sourceSystem()))throw new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,"质量事件来源必须为WMS或OMS");var claim=inbox.claim(event.sourceSystem(),event.eventCode(),event.eventType(),CONSUMER,event.sourceSystem()+":"+event.eventCode());if(claim==MasterDataEventConsumeLogPort.ClaimResult.ALREADY_SUCCEEDED)return;if(claim==MasterDataEventConsumeLogPort.ClaimResult.IN_PROGRESS)throw new BusinessException(ErrorCode.IDEMPOTENCY_CONFLICT,"质量来源事件正在处理");payloads.save(event.sourceSystem(),event.eventCode(),CONSUMER,event);try{var context=new CommandContext(0,event.sourceSystem(),0,null,event.sourceSystem()+"-"+event.eventCode(),null,event.sourceSystem()+":"+event.eventCode(),Set.of("supplier:quality:create"));issues.create(event.supplierId(),event.sourceSystem(),event.sourceNo(),event.issueType(),event.severity(),event.description(),context);inbox.markSucceeded(event.sourceSystem(),event.eventCode(),CONSUMER,false);}catch(RuntimeException exception){inbox.recordFailure(event.sourceSystem(),event.eventCode(),event.eventType(),CONSUMER,event.sourceSystem()+":"+event.eventCode(),exception.getMessage());throw exception;}}}
